window.bookSummaryJSON = "<p>King Arthur lives, but the war isn't over, and distinguishing between friends and foes has never been more difficult. <i>A Long Cloud </i>takes Myrddin and Nell into England. And it is there, in the heart of Modred's domain, that the truth about Myrddin's parentage is finally revealed.</p> <p><i>A Long Cloud</i> is the long-awaited fourth installment in the Lion of Wales series.</p> <p><b>Complete series listening order</b>: <i>Cold My Heart</i>,<i> The Oaken Door</i>,<i> Of Men and Dragons</i>,<i> A Long Cloud</i>,<i> Frost Against the Hilt.</i></p>"; 
